public int active()
{
    int ret = next active();
    if(ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
    {
        this.object(fieldNum(SalesAgreementHeaderDefault, CustomerMethodOfPayment)).mandatory(true);
    }
    return ret;

}

public boolean validateWrite()
{
    boolean ret = next validateWrite();

    if (ret && ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
    {
        ret = ETGSalesAgreementMandatoryValidation::validateFormHeaders(this.formRun());
    }

    return ret;
}
